import sys
import bisect


def main():
    n = int(sys.stdin.readline())
    events = list(map(int, sys.stdin.readline().split()))
    untreated_crimes = 0
    officers = []

    for e in events:
        if e == -1:
            if officers:
                officers.pop()
            else:
                untreated_crimes += 1
        else:
            officers += [True] * e

    print(untreated_crimes)


if __name__ == '__main__':
    main()
